{{ dashboard["dashboard_sections"][0]["widgets"].clear() }}

{%- set _ = dashboard.update({
    "default_storyboard": "Main",
    "storyboards": [
        {
            "name": "Main",
            "value": "{}"
        }
    ]
    })

-%}

{%-
    set sb = {
        "stage": {
            "size": {
                "width": 1920,
                "height": 3200
            },
            "background": {
                "fill": null,
                "src": null,
                "gradient": {
                    "color1": "#222222",
                    "color2": "#2C2C2C",
                    "type": "linear",
                    "rotation": 90
                }
            },
            "theme": "dark",
            "autoFitByDefault": false,
            "autoFitMinWidth": 800
        },
        "widgets": [],
        "shapes": [],
        "lines": [],
        "sbBookmarkList": [] 
    }
-%}


{% if conversation_id is  not defined %}
   {%- set conversation_id = "unknown" -%}
   {%- set message = "conversation_id not found in context" -%}
{%- else -%}
    {%- set message = "" -%}
{% endif %}

{%-
   set cfxql_query = "conversation_id = '"+str(conversation_id)+"' and item_type = 'widget'"
-%}

{%-
    set rows = engine.query_stream_data("rda_ai_canvas", cfxql_query=cfxql_query, limit=100, max_rows=100, sorting=[{"timestamp": "asc"}])
-%}

{%- if not rows -%}
  {%- if not message -%}
    {%- set message = "This Canvas does not have any widgets added to it." -%}
  {%- endif -%}
   {%- set _ = dashboard.pop("default_storyboard", "") -%}

    {{ dashboard["dashboard_sections"][0]["widgets"].append({
        "widget_type": "label",
        "height": 1,
        "max_width": 12,
        "label": message,
        "widget_id": "header1"
    }) }}

 {%- endif -%}

{%-
    for w in rows
-%}
    {%-
        set wdef = json_loads(w.get('content', '{}'))
    -%}

    {%-
        set layout = json_loads(w.get('layoutContent', '{}'))
    -%}

        {{ dashboard["dashboard_sections"][0]["widgets"].append(wdef) }}

        {{ sb["widgets"].append(layout) }}

{%-
    endfor
-%}

{%-
  set _ = dashboard["storyboards"][0].update({ "value": json_dumps(sb) })
-%}

